274	/********************************************************************
275	 * Write fabric key of the module graph for FPGA device to a file
276	 *******************************************************************/
277	template <class T>
278	int write_fabric_key_template(const T& openfpga_ctx, const Command& cmd,
279	                              const CommandContext& cmd_context) {
280	  CommandOptionId opt_verbose = cmd.option("verbose");
281	  CommandOptionId opt_include_module_keys = cmd.option("include_module_keys");
282	
283	  /* Check the option '--file' is enabled or not
284	   * Actually, it must be enabled as the shell interface will check
285	   * before reaching this fuction
286	   */
287	  CommandOptionId opt_file = cmd.option("file");
288	  VTR_ASSERT(true == cmd_context.option_enable(cmd, opt_file));
289	  VTR_ASSERT(false == cmd_context.option_value(cmd, opt_file).empty());
290	
291	  /* Write fabric key to a file */
292	  return write_fabric_key_to_xml_file(
293	    openfpga_ctx.module_graph(), cmd_context.option_value(cmd, opt_file),
294	    openfpga_ctx.arch().config_protocol,
295	    openfpga_ctx.blwl_shift_register_banks(),
296	    cmd_context.option_enable(cmd, opt_include_module_keys),
297	    cmd_context.option_enable(cmd, opt_verbose));
298	}
