300	/********************************************************************
301	 * Write hierarchy of the module graph for FPGA device to a file
302	 *******************************************************************/
303	template <class T>
304	int write_fabric_hierarchy_template(const T& openfpga_ctx, const Command& cmd,
305	                                    const CommandContext& cmd_context) {
306	  CommandOptionId opt_verbose = cmd.option("verbose");
307	  CommandOptionId opt_exclude_empty_modules =
308	    cmd.option("exclude_empty_modules");
309	
310	  /* Check the option '--file' is enabled or not
311	   * Actually, it must be enabled as the shell interface will check
312	   * before reaching this fuction
313	   */
314	  CommandOptionId opt_file = cmd.option("file");
315	  VTR_ASSERT(true == cmd_context.option_enable(cmd, opt_file));
316	  VTR_ASSERT(false == cmd_context.option_value(cmd, opt_file).empty());
317	
318	  CommandOptionId opt_module = cmd.option("module");
319	  std::string root_module =
320	    openfpga_ctx.module_name_map().name(generate_fpga_top_module_name());
321	  if (true == cmd_context.option_enable(cmd, opt_module)) {
322	    root_module = cmd_context.option_value(cmd, opt_module);
323	  }
324	
325	  CommandOptionId opt_filter = cmd.option("filter");
326	  std::string filter("*");
327	  if (true == cmd_context.option_enable(cmd, opt_filter)) {
328	    filter = cmd_context.option_value(cmd, opt_filter);
329	  }
330	
331	  /* Default depth requirement, will not stop until the leaf */
332	  int depth = -1;
333	  CommandOptionId opt_depth = cmd.option("depth");
334	  if (true == cmd_context.option_enable(cmd, opt_depth)) {
335	    depth = std::atoi(cmd_context.option_value(cmd, opt_depth).c_str());
336	    /* Error out if we have negative depth */
337	    if (0 > depth) {
338	      VTR_LOG_ERROR(
339	        "Invalid depth '%d' which should be 0 or a positive number!\n", depth);
340	      return CMD_EXEC_FATAL_ERROR;
341	    }
342	  }
343	
344	  std::string hie_file_name = cmd_context.option_value(cmd, opt_file);
345	
346	  /* Write hierarchy to a file */
347	  return write_fabric_hierarchy_to_text_file(
348	    openfpga_ctx.module_graph(), openfpga_ctx.module_name_map(), hie_file_name,
349	    root_module, filter, size_t(depth),
350	    cmd_context.option_enable(cmd, opt_exclude_empty_modules),
351	    cmd_context.option_enable(cmd, opt_verbose));
352	}
