379	/********************************************************************
380	 * Write the boundary timing information to a file
381	 *******************************************************************/
382	template <class T>
383	int write_boundary_timing_info_template(const Command& cmd,
384	                                        const CommandContext& cmd_context) {
385	  CommandOptionId opt_verbose = cmd.option("verbose");
386	
387	  /* Check the option '--file' is enabled or not
388	   * Actually, it must be enabled as the shell interface will check
389	   * before reaching this fuction
390	   */
391	  CommandOptionId opt_file = cmd.option("file");
392	  CommandOptionId opt_default_timing_value = cmd.option("default_timing_value");
393	  CommandOptionId opt_pin_table = cmd.option("pin_table");
394	  CommandOptionId opt_pin_table_dir_convention =
395	    cmd.option("pin_table_direction_convention");
396	
397	  std::string pin_table_fname = cmd_context.option_value(cmd, opt_pin_table);
398	  bool verbose_output = cmd_context.option_enable(cmd, opt_verbose);
399	  VTR_ASSERT(true == cmd_context.option_enable(cmd, opt_file));
400	  VTR_ASSERT(false == cmd_context.option_value(cmd, opt_file).empty());
401	
402	  std::string file_name = cmd_context.option_value(cmd, opt_file);
403	  std::string default_timimg_value = "0";
404	  if (cmd_context.option_enable(cmd, opt_default_timing_value)) {
405	    default_timimg_value =
406	      cmd_context.option_value(cmd, opt_default_timing_value);
407	  }
408	  e_pin_table_direction_convention pin_table_dir_convention =
409	    e_pin_table_direction_convention::EXPLICIT;
410	  if (cmd_context.option_enable(cmd, opt_pin_table_dir_convention)) {
411	    std::string pin_table_dir_convention_str =
412	      cmd_context.option_value(cmd, opt_pin_table_dir_convention);
413	    if (pin_table_dir_convention_str ==
414	        std::string(PIN_TABLE_DIRECTION_CONVENTION_STRING.at(
415	          e_pin_table_direction_convention::EXPLICIT))) {
416	      pin_table_dir_convention = e_pin_table_direction_convention::EXPLICIT;
417	    } else if (pin_table_dir_convention_str ==
418	               std::string(PIN_TABLE_DIRECTION_CONVENTION_STRING.at(
419	                 e_pin_table_direction_convention::QUICKLOGIC))) {
420	      pin_table_dir_convention = e_pin_table_direction_convention::QUICKLOGIC;
421	    } else {
422	      VTR_LOG_ERROR(
423	        "Invalid pin naming convention ('%s') to identify port direction for "
424	        "pin table! Expect ['%s'|'%s'].\n",
425	        pin_table_dir_convention_str.c_str(),
426	        PIN_TABLE_DIRECTION_CONVENTION_STRING.at(
427	          e_pin_table_direction_convention::EXPLICIT),
428	        PIN_TABLE_DIRECTION_CONVENTION_STRING.at(
429	          e_pin_table_direction_convention::QUICKLOGIC));
430	    }
431	  }
432	
433	  /* Parse the fabric key from an XML file */
434	  IoPinTable io_pin_table =
435	    read_csv_io_pin_table(pin_table_fname.c_str(), pin_table_dir_convention);
436	  VTR_LOG("Read the I/O pin table from a csv file: %s.\n",
437	          pin_table_fname.c_str());
438	
439	  BoundaryTiming bd_timing;
440	  for (auto pin_id : io_pin_table.pins()) {
441	    auto pin = io_pin_table.external_pin(pin_id);
442	    bd_timing.create_pin_boundary_timing(pin, default_timimg_value,
443	                                         default_timimg_value);
444	  }
445	  VTR_LOGV(verbose_output, "write boundary timing file to: %s \n",
446	           file_name.c_str());
447	  /* Write hierarchy to a file */
448	  return write_xml_boundary_timing(file_name.c_str(), bd_timing);
449	}
