451	/********************************************************************
452	 * Add fpga_core module to the module graph
453	 *******************************************************************/
454	template <class T>
455	int add_fpga_core_to_fabric_template(T& openfpga_ctx, const Command& cmd,
456	                                     const CommandContext& cmd_context) {
457	  CommandOptionId opt_frame_view = cmd.option("frame_view");
458	  bool frame_view = cmd_context.option_enable(cmd, opt_frame_view);
459	  CommandOptionId opt_verbose = cmd.option("verbose");
460	  bool verbose_output = cmd_context.option_enable(cmd, opt_verbose);
461	
462	  CommandOptionId opt_inst_name = cmd.option("instance_name");
463	  std::string core_inst_name = generate_fpga_core_instance_name();
464	  if (true == cmd_context.option_enable(cmd, opt_inst_name)) {
465	    core_inst_name = cmd_context.option_value(cmd, opt_inst_name);
466	  }
467	
468	  /* Handle I/O naming rules if defined */
469	  CommandOptionId opt_io_naming = cmd.option("io_naming");
470	  if (true == cmd_context.option_enable(cmd, opt_io_naming)) {
471	    read_xml_io_name_map(cmd_context.option_value(cmd, opt_io_naming).c_str(),
472	                         openfpga_ctx.mutable_io_name_map());
473	  }
474	
475	  return add_fpga_core_to_device_module_graph(
476	    openfpga_ctx.mutable_module_graph(), openfpga_ctx.mutable_module_name_map(),
477	    openfpga_ctx.io_name_map(), core_inst_name, frame_view, verbose_output);
478	}
